<span class="line">        <span class="token keyword">new</span> <span class="token class-name">TrapdoorBlock</span><span class="token punctuation">(</span><span class="token class-name">BlockSetType</span><span class="token punctuation">.</span><span class="token constant">IRON</span><span class="token punctuation">,</span></span>
